import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './App.css';
import Navbar from "./components/Navbar";

function App() {
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [isRegisterMode, setIsRegisterMode] = useState(false);

  const [usuario, setUsuario] = useState('');
  const [password, setPassword] = useState('');
  const [nuevoRol, setNuevoRol] = useState('vendedor');

  const [userRole, setUserRole] = useState('');
  const [view, setView] = useState('dashboard');

  const [stats, setStats] = useState({
    total_productos: 0,
    valor_inventario: 0,
    bajo_stock: 0
  });

  const [productos, setProductos] = useState([]);
  const [busqueda, setBusqueda] = useState('');

  const [showForm, setShowForm] = useState(false);
  const [editMode, setEditMode] = useState(false);
  const [selectedId, setSelectedId] = useState(null);

  const [nuevoProd, setNuevoProd] = useState({
    nombre: '',
    stock: '',
    precio_venta: ''
  });

  const cargarDatos = async () => {
    const resStats = await axios.get('http://localhost:5000/api/stats');
    const resProds = await axios.get('http://localhost:5000/api/productos');
    setStats(resStats.data);
    setProductos(resProds.data);
  };

  useEffect(() => {
    if (isLoggedIn) cargarDatos();
  }, [isLoggedIn]);

  const buscarProductos = async (texto) => {
    setBusqueda(texto);

    if (texto.trim() === '') {
      cargarDatos();
      return;
    }

    const res = await axios.get(
      `http://localhost:5000/api/productos/buscar?q=${texto}`
    );
    setProductos(res.data);
  };

  const handleLogin = async () => {
    const res = await axios.post('http://localhost:5000/api/login', {
      usuario,
      clave: password
    });

    if (res.data.success) {
      setIsLoggedIn(true);
      setUserRole(res.data.rol);
    }
  };

  const handleRegister = async () => {
    await axios.post('http://localhost:5000/api/register', {
      usuario,
      clave: password,
      rol: nuevoRol
    });
    alert("Registro exitoso");
    setIsRegisterMode(false);
  };
const guardarProducto = async () => {
  const data = {
    nombre: nuevoProd.nombre,
    categoria: "General", // <--- Agrega esto
    stock: Number(nuevoProd.stock),
    precio_compra: 0,      // <--- Agrega esto
    precio_venta: Number(nuevoProd.precio_venta),
    fecha_caducidad: null  // <--- Agrega esto
  };


    if (editMode) {
      await axios.put(
        `http://localhost:5000/api/productos/${selectedId}`,
        data
      );
    } else {
      await axios.post('http://localhost:5000/api/productos', data);
    }

    setShowForm(false);
    setEditMode(false);
    setNuevoProd({ nombre: '', stock: '', precio_venta: '' });
    cargarDatos();
  };

  const prepararEdicion = (p) => {
    setSelectedId(p.id);
    setNuevoProd({
      nombre: p.nombre,
      stock: p.stock,
      precio_venta: p.precio_venta
    });
    setEditMode(true);
    setShowForm(true);
  };

  const eliminar = async (id) => {
    if (window.confirm("¿Borrar producto?")) {
      await axios.delete(`http://localhost:5000/api/productos/${id}`);
      cargarDatos();
    }
  };

  if (!isLoggedIn) {
    return (
      <div className="login-container">
        <div className="login-card">
          <h2>{isRegisterMode ? 'Crear Cuenta' : 'Iniciar Sesión'}</h2>

          <input
            placeholder="Usuario"
            value={usuario}
            onChange={e => setUsuario(e.target.value)}
          />

          <input
            type="password"
            placeholder="Contraseña"
            value={password}
            onChange={e => setPassword(e.target.value)}
          />

          {isRegisterMode && (
            <select value={nuevoRol} onChange={e => setNuevoRol(e.target.value)}>
              <option value="vendedor">Vendedor</option>
              <option value="admin">Administrador</option>
            </select>
          )}

          {isRegisterMode ? (
            <button onClick={handleRegister}>Registrarse</button>
          ) : (
            <button onClick={handleLogin}>Entrar</button>
          )}

          <p
            onClick={() => setIsRegisterMode(!isRegisterMode)}
            style={{ cursor: 'pointer' }}
          >
            {isRegisterMode ? 'Ya tengo cuenta' : 'Crear cuenta'}
          </p>
        </div>
      </div>
    );
  }

  return (
    <div className="main-wrapper">
      <Navbar
        setView={setView}
        userRole={userRole}
        logout={() => setIsLoggedIn(false)}
      />

      <main className="content-area">
        {view === "dashboard" ? (
          <div className="dashboard-grid">
            <div className="card">
              <h3>⚠️ Bajo Stock</h3>
              <p>{stats.bajo_stock} productos</p>
            </div>
            <div className="card">
              <h3>📊 Estadísticas</h3>
              <p>Total: {stats.total_productos}</p>
              <p>Valor: ${stats.valor_inventario}</p>
            </div>
          </div>
        ) : (
          <div className="card">
            <button onClick={() => setShowForm(!showForm)}>+ Agregar</button>

            <input
              type="text"
              placeholder="Buscar producto o marca..."
              value={busqueda}
              onChange={(e) => buscarProductos(e.target.value)}
              style={{ marginBottom: '10px', padding: '6px', width: '250px' }}
            />

            {showForm && (
              <>
                <input
                  placeholder="Nombre"
                  value={nuevoProd.nombre}
                  onChange={e => setNuevoProd({ ...nuevoProd, nombre: e.target.value })}
                />
                <input
                  placeholder="Stock"
                  type="number"
                  value={nuevoProd.stock}
                  onChange={e => setNuevoProd({ ...nuevoProd, stock: e.target.value })}
                />
                <input
                  placeholder="Precio"
                  type="number"
                  value={nuevoProd.precio_venta}
                  onChange={e => setNuevoProd({ ...nuevoProd, precio_venta: e.target.value })}
                />
                <button onClick={guardarProducto}>Guardar</button>
              </>
            )}

            <table>
              <tbody>
                {productos.map(p => (
                  <tr key={p.id}>
                    <td>{p.nombre}</td>
                    <td>{p.stock}</td>
                    <td>${p.precio_venta}</td>
                    <td>
                      <button onClick={() => prepararEdicion(p)}>✏️</button>
                      <button onClick={() => eliminar(p.id)}>🗑️</button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </main>
    </div>
  );
}

export default App;
